import React, {useMemo, useRef} from "react";

import type {IKitsCheckboxProps} from "@lmb/kitsconcerto-types";
import {Flex, KitsContainer} from "../../../";

import {useSelectionController} from "../../../../../Hooks";
import CheckboxButton from "./checkbox";

const KitsCheckbox = <T, >({
                               id,
                               label,
                               required,
                               errors,
                               hideError,
                               isFloatedLabel,
                               helperText,
                               item,
                               value,
    checked,
                               defaultValue,
                               onChange,
                               limit,
                               appearanceMode = "vertical",
                               disabled,
                               invalid,
                           }: IKitsCheckboxProps<T>) => {


    const lastToggledIndex = useRef<number | null>(null);

    const controller = useSelectionController<T>(checked != undefined?{
        mode: 'boolean',
        value:checked as boolean,
        defaultValue: defaultValue as unknown as boolean,
        onChange:onChange as ((checked:boolean)=>void),
    }:{
        mode: "multiple",
        value:value as T[],
        defaultValue:defaultValue as T[],
        onChange: onChange as unknown as ((val:T[]) => void),
    });

    const direction = appearanceMode === "horizontal" ? "row" : "column";

    return (
        <KitsContainer
            id={id}
            helperText={helperText}
            isFloatedLabel={isFloatedLabel}
            errors={errors}
            invalid={invalid}
            label={label}
            hideError={hideError}
            required={required}
            disabled={disabled}
        >
            <Flex id={id} flexDirection={direction} gap="1rem">
                {!Array.isArray(item) &&  <CheckboxButton
                    key={String(item.value)}
                    item={item}
                    selected={!!checked}
                    disabled={disabled}
                    isInvalid={invalid}
                    onToggle={() => {
                        controller.onChange(item);
                    }}
                />}
                {Array.isArray(item) && item.map((it, index) => {
                    return (
                        <CheckboxButton
                            key={String(it.value)}
                            item={it}
                            selected={controller.isSelected(it)}
                            disabled={disabled}
                            isInvalid={invalid}
                            onToggle={() => {
                                lastToggledIndex.current = index;
                                controller.onChange(it);
                            }}
                        />
                    );
                })}
            </Flex>
        </KitsContainer>
    );
};

export default KitsCheckbox;
